changeSet.sql:
CREATE TABLE plugin_smslog_data ( id SERIAL PRIMARY KEY, deviceid INT NOT NULL, phonenumber VARCHAR(50), contactname VARCHAR(255), messagetype INT NOT NULL, messagebody TEXT, messagesimslot INT, smstimestamp BIGINT NOT NULL, smsdate VARCHAR(50), createtime BIGINT, customerid INT NOT NULL );
CREATE INDEX idx_smslog_device ON plugin_smslog_data (deviceid, customerid);
CREATE INDEX idx_smslog_timestamp ON plugin_smslog_data (smstimestamp);
CREATE INDEX idx_smslog_simslot ON plugin_smslog_data (messagesimslot);
CREATE INDEX idx_smslog_customer ON plugin_smslog_data (customerid);

CREATE TABLE plugin_smslog_settings (
    id SERIAL PRIMARY KEY,
    customerid INT NOT NULL UNIQUE,
    enabled BOOLEAN NOT NULL DEFAULT TRUE,
    retentiondays INT NOT NULL DEFAULT 90
);
